import{_ as l,c as i,b as t,a as s,d as a,e as p,r as c,o}from"./app-CvT2DUHU.js";const d={},r={href:"https://github.com/coolclaws/deerflow-book",target:"_blank",rel:"noopener noreferrer"};function u(g,n){const e=c("ExternalLinkIcon");return o(),i("div",null,[n[2]||(n[2]=t(`<h1 id="第-2-章-仓库全景与技术栈" tabindex="-1"><a class="header-anchor" href="#第-2-章-仓库全景与技术栈"><span>第 2 章　仓库全景与技术栈</span></a></h1><h2 id="_2-1-目录结构" tabindex="-1"><a class="header-anchor" href="#_2-1-目录结构"><span>2.1　目录结构</span></a></h2><p>拿到 DeerFlow 的源码，第一件事是看目录结构。整个仓库的布局清晰、职责分明：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">deer-flow/</span>
<span class="line">├── backend/                  # 后端核心（Python）</span>
<span class="line">│   ├── src/</span>
<span class="line">│   │   ├── agents/           # Agent 定义（lead_agent、middlewares）</span>
<span class="line">│   │   ├── channels/         # IM 频道集成（Telegram、Slack、飞书）</span>
<span class="line">│   │   ├── client.py         # 嵌入式 Python 客户端</span>
<span class="line">│   │   ├── community/        # 社区贡献的工具和沙箱实现</span>
<span class="line">│   │   ├── config/           # 配置加载和解析</span>
<span class="line">│   │   ├── gateway/          # Gateway API（FastAPI）</span>
<span class="line">│   │   ├── mcp/              # MCP Server 集成</span>
<span class="line">│   │   ├── models/           # 模型封装和适配</span>
<span class="line">│   │   ├── reflection/       # 反思机制</span>
<span class="line">│   │   ├── sandbox/          # 沙箱执行引擎</span>
<span class="line">│   │   ├── skills/           # Skills 加载器</span>
<span class="line">│   │   ├── subagents/        # 子智能体管理</span>
<span class="line">│   │   ├── tools/            # 内置工具（搜索、文件、bash）</span>
<span class="line">│   │   └── utils/            # 通用工具</span>
<span class="line">│   └── pyproject.toml        # Python 依赖定义</span>
<span class="line">├── frontend/                 # 前端（Next.js + React）</span>
<span class="line">│   ├── src/                  # 前端源码</span>
<span class="line">│   └── package.json          # Node 依赖定义</span>
<span class="line">├── skills/                   # 技能定义目录</span>
<span class="line">│   └── public/               # 内置技能</span>
<span class="line">│       ├── deep-research/    # 深度研究</span>
<span class="line">│       ├── data-analysis/    # 数据分析</span>
<span class="line">│       ├── ppt-generation/   # PPT 生成</span>
<span class="line">│       ├── web-design-guidelines/ # 网页设计</span>
<span class="line">│       ├── image-generation/ # 图片生成</span>
<span class="line">│       ├── video-generation/ # 视频生成</span>
<span class="line">│       ├── consulting-analysis/   # 咨询分析</span>
<span class="line">│       ├── chart-visualization/   # 图表可视化</span>
<span class="line">│       ├── claude-to-deerflow/    # Claude Code 集成</span>
<span class="line">│       └── ...               # 更多技能</span>
<span class="line">├── docker/                   # Docker 配置和 nginx</span>
<span class="line">├── scripts/                  # 启动、检查、清理脚本</span>
<span class="line">├── config.example.yaml       # 配置模板</span>
<span class="line">├── extensions_config.example.json  # MCP 和 Skills 状态配置模板</span>
<span class="line">└── Makefile                  # 统一入口命令</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>几个值得注意的设计决策：</p><ol><li><strong>backend 和 frontend 完全分离</strong>——后端是纯 Python，前端是纯 Next.js，通过 API 和 SSE 通信。</li><li><strong>skills 独立于 backend</strong>——技能是 Markdown 文件，不是代码。这意味着非开发者也可以编写和贡献技能。</li><li><strong>community 目录</strong>——社区贡献的工具（Tavily、Jina、InfoQuest）和沙箱实现（AIO Sandbox）放在 <code>src/community/</code> 下，与核心代码隔离。</li></ol><h2 id="_2-2-核心依赖" tabindex="-1"><a class="header-anchor" href="#_2-2-核心依赖"><span>2.2　核心依赖</span></a></h2><p>打开 <code>backend/pyproject.toml</code>，DeerFlow 的技术栈一目了然：</p><div class="language-toml line-numbers-mode" data-highlighter="prismjs" data-ext="toml" data-title="toml"><pre><code><span class="line"><span class="token comment"># 摘自 backend/pyproject.toml</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">[</span><span class="token table class-name">project</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token key property">name</span> <span class="token punctuation">=</span> <span class="token string">&quot;deer-flow&quot;</span></span>
<span class="line"><span class="token key property">version</span> <span class="token punctuation">=</span> <span class="token string">&quot;0.1.0&quot;</span></span>
<span class="line"><span class="token key property">description</span> <span class="token punctuation">=</span> <span class="token string">&quot;LangGraph-based AI agent system with sandbox execution capabilities&quot;</span></span>
<span class="line"><span class="token key property">requires-python</span> <span class="token punctuation">=</span> <span class="token string">&quot;&gt;=3.12&quot;</span></span>
<span class="line"><span class="token key property">dependencies</span> <span class="token punctuation">=</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token string">&quot;agent-sandbox&gt;=0.0.19&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;fastapi&gt;=0.115.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;httpx&gt;=0.28.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;kubernetes&gt;=30.0.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langchain&gt;=1.2.3&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langchain-anthropic&gt;=1.3.4&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langchain-deepseek&gt;=1.0.1&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langchain-openai&gt;=1.1.7&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langgraph&gt;=1.0.6&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langgraph-api&gt;=0.7.0,&lt;0.8.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langgraph-runtime-inmem&gt;=0.22.1&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;pydantic&gt;=2.12.5&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;sse-starlette&gt;=2.1.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;tavily-python&gt;=0.7.17&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;uvicorn[standard]&gt;=0.34.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;langchain-google-genai&gt;=4.2.1&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;slack-sdk&gt;=3.33.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;python-telegram-bot&gt;=21.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token comment"># ...更多依赖</span></span>
<span class="line"><span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>逐层拆解这些依赖的角色：</p><h3 id="langgraph-编排引擎" tabindex="-1"><a class="header-anchor" href="#langgraph-编排引擎"><span>LangGraph：编排引擎</span></a></h3><p>DeerFlow 的 Agent 编排建立在 <strong>LangGraph</strong> 之上。LangGraph 提供了有状态的、可持久化的 Agent 运行时：</p><ul><li><code>langgraph&gt;=1.0.6</code>：核心图编排引擎</li><li><code>langgraph-api&gt;=0.7.0</code>：LangGraph Server API</li><li><code>langgraph-runtime-inmem&gt;=0.22.1</code>：内存运行时</li><li><code>langgraph-checkpoint-sqlite&gt;=3.0.3</code>：SQLite 持久化</li></ul><p>DeerFlow 用 LangGraph 的 <code>create_agent</code> 创建 Lead Agent，用 middleware 链处理上下文摘要、记忆注入、子智能体限流等横切关注点。</p><h3 id="langchain-模型和工具适配层" tabindex="-1"><a class="header-anchor" href="#langchain-模型和工具适配层"><span>LangChain：模型和工具适配层</span></a></h3><p>LangChain 系列库负责统一不同模型提供商的接口：</p><ul><li><code>langchain&gt;=1.2.3</code>：核心抽象</li><li><code>langchain-anthropic&gt;=1.3.4</code>：Claude 系列</li><li><code>langchain-openai&gt;=1.1.7</code>：OpenAI / 兼容 API</li><li><code>langchain-deepseek&gt;=1.0.1</code>：DeepSeek</li><li><code>langchain-google-genai&gt;=4.2.1</code>：Gemini</li><li><code>langchain-mcp-adapters&gt;=0.1.0</code>：MCP 工具适配</li></ul><h3 id="fastapi-sse-api-层" tabindex="-1"><a class="header-anchor" href="#fastapi-sse-api-层"><span>FastAPI + SSE：API 层</span></a></h3><ul><li><code>fastapi&gt;=0.115.0</code>：Gateway API 框架</li><li><code>sse-starlette&gt;=2.1.0</code>：Server-Sent Events 流式推送</li><li><code>uvicorn[standard]&gt;=0.34.0</code>：ASGI 服务器</li></ul><h3 id="沙箱和执行环境" tabindex="-1"><a class="header-anchor" href="#沙箱和执行环境"><span>沙箱和执行环境</span></a></h3><ul><li><code>agent-sandbox&gt;=0.0.19</code>：沙箱抽象</li><li><code>kubernetes&gt;=30.0.0</code>：K8s 集成（生产环境 Pod 管理）</li></ul><h3 id="im-频道集成" tabindex="-1"><a class="header-anchor" href="#im-频道集成"><span>IM 频道集成</span></a></h3><ul><li><code>slack-sdk&gt;=3.33.0</code>：Slack Socket Mode</li><li><code>python-telegram-bot&gt;=21.0</code>：Telegram Bot API</li><li><code>lark-oapi&gt;=1.4.0</code>：飞书 / Lark WebSocket</li></ul><h2 id="_2-3-前端技术栈" tabindex="-1"><a class="header-anchor" href="#_2-3-前端技术栈"><span>2.3　前端技术栈</span></a></h2><p>前端采用 <strong>Next.js + React</strong>，实现实时流式 UI：</p><ul><li><strong>Next.js</strong>：全栈 React 框架，提供路由和 SSR</li><li><strong>pnpm</strong>：包管理器（仓库使用 pnpm workspace）</li><li><strong>实时流式渲染</strong>：通过 SSE 接收后端的 Agent 执行事件，增量渲染 AI 回复、工具调用、文件产出</li></ul><p>前端通过 nginx 反向代理统一暴露在 <code>localhost:2026</code>，API 请求转发到 Gateway（8001）和 LangGraph Server（2024）。</p><h2 id="_2-4-配置体系" tabindex="-1"><a class="header-anchor" href="#_2-4-配置体系"><span>2.4　配置体系</span></a></h2><p>DeerFlow 的配置分为三层：</p><p><strong>第一层：<code>config.yaml</code></strong> —— 核心配置文件，包含模型定义、工具配置、沙箱模式、子智能体超时、Skills 路径、摘要策略、记忆系统等。这是你部署 DeerFlow 时必须编辑的文件。</p><p><strong>第二层：<code>extensions_config.json</code></strong> —— MCP Server 和 Skills 启用状态。这个文件允许运行时动态开关 MCP 服务和技能，不需要重启。</p><p><strong>第三层：<code>.env</code></strong> —— API 密钥和敏感配置。DeerFlow 的 <code>config.yaml</code> 支持 <code>$ENV_VAR</code> 语法引用环境变量，所以密钥不需要写在配置文件里。</p><h2 id="_2-5-支持的模型" tabindex="-1"><a class="header-anchor" href="#_2-5-支持的模型"><span>2.5　支持的模型</span></a></h2><p>DeerFlow 是模型无关的（model-agnostic），支持任何实现 OpenAI 兼容 API 的模型。配置文件中提供了以下模型的示例：</p><table><thead><tr><th>模型</th><th>LangChain 适配类</th><th>特殊能力</th></tr></thead><tbody><tr><td>Claude 3.5 Sonnet</td><td><code>langchain_anthropic:ChatAnthropic</code></td><td>Thinking、Vision</td></tr><tr><td>GPT-4</td><td><code>langchain_openai:ChatOpenAI</code></td><td>Vision</td></tr><tr><td>Gemini 2.5 Pro</td><td><code>langchain_google_genai:ChatGoogleGenerativeAI</code></td><td>Vision</td></tr><tr><td>DeepSeek V3</td><td><code>src.models.patched_deepseek:PatchedChatDeepSeek</code></td><td>Thinking</td></tr><tr><td>豆包 Seed 1.8</td><td><code>src.models.patched_deepseek:PatchedChatDeepSeek</code></td><td>Thinking、Vision</td></tr><tr><td>Kimi K2.5</td><td><code>src.models.patched_deepseek:PatchedChatDeepSeek</code></td><td>Thinking、Vision</td></tr><tr><td>OpenAI 兼容</td><td><code>langchain_openai:ChatOpenAI</code></td><td>取决于提供商</td></tr></tbody></table><p>DeerFlow 在最佳实践中推荐的模型特性包括：长上下文窗口（100K+ tokens）、推理能力（reasoning）、多模态输入、可靠的工具调用（tool-use）。</p><h2 id="_2-6-运行时架构" tabindex="-1"><a class="header-anchor" href="#_2-6-运行时架构"><span>2.6　运行时架构</span></a></h2><p>一个运行中的 DeerFlow 实例由四个服务组成：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">用户浏览器</span>
<span class="line">    │</span>
<span class="line">    ▼</span>
<span class="line">  nginx (端口 2026)           ← 反向代理，统一入口</span>
<span class="line">    ├── /api/gateway/* ──→ Gateway API (端口 8001)    ← FastAPI，管理接口</span>
<span class="line">    ├── /api/langgraph/* ──→ LangGraph Server (端口 2024) ← Agent 运行时</span>
<span class="line">    └── /* ──────────────→ Frontend (端口 3000)       ← Next.js UI</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Gateway API 负责配置管理、文件上传、技能管理等&quot;管控面&quot;操作。LangGraph Server 负责 Agent 的实际执行——接收用户消息、运行 Lead Agent、调度子智能体、流式返回结果。</p><h2 id="小结" tabindex="-1"><a class="header-anchor" href="#小结"><span>小结</span></a></h2><ul><li><strong>目录结构清晰</strong>：backend（Python Agent 引擎）/ frontend（Next.js 流式 UI）/ skills（Markdown 技能定义）/ docker（容器化部署）四大模块。</li><li><strong>核心引擎是 LangGraph + LangChain</strong>：LangGraph 负责有状态的 Agent 编排，LangChain 负责模型和工具的统一抽象。</li><li><strong>配置三层分离</strong>：<code>config.yaml</code>（核心配置）+ <code>extensions_config.json</code>（运行时开关）+ <code>.env</code>（密钥）。</li><li><strong>模型无关</strong>：通过 LangChain 适配层支持 Claude / GPT / Gemini / DeepSeek / 豆包 / Kimi 等，任何 OpenAI 兼容 API 均可接入。</li><li><strong>四服务架构</strong>：nginx + Frontend + Gateway + LangGraph Server，通过 SSE 实现实时流式交互。</li></ul><hr>`,43)),s("p",null,[n[1]||(n[1]=a("来源: ",-1)),s("a",r,[n[0]||(n[0]=a("DeerFlow Book",-1)),p(e)])])])}const h=l(d,[["render",u]]),m=JSON.parse('{"path":"/docs/Agent/DeerFlow/02-repo-overview.html","title":"第 2 章　仓库全景与技术栈","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"2.1　目录结构","slug":"_2-1-目录结构","link":"#_2-1-目录结构","children":[]},{"level":2,"title":"2.2　核心依赖","slug":"_2-2-核心依赖","link":"#_2-2-核心依赖","children":[{"level":3,"title":"LangGraph：编排引擎","slug":"langgraph-编排引擎","link":"#langgraph-编排引擎","children":[]},{"level":3,"title":"LangChain：模型和工具适配层","slug":"langchain-模型和工具适配层","link":"#langchain-模型和工具适配层","children":[]},{"level":3,"title":"FastAPI + SSE：API 层","slug":"fastapi-sse-api-层","link":"#fastapi-sse-api-层","children":[]},{"level":3,"title":"沙箱和执行环境","slug":"沙箱和执行环境","link":"#沙箱和执行环境","children":[]},{"level":3,"title":"IM 频道集成","slug":"im-频道集成","link":"#im-频道集成","children":[]}]},{"level":2,"title":"2.3　前端技术栈","slug":"_2-3-前端技术栈","link":"#_2-3-前端技术栈","children":[]},{"level":2,"title":"2.4　配置体系","slug":"_2-4-配置体系","link":"#_2-4-配置体系","children":[]},{"level":2,"title":"2.5　支持的模型","slug":"_2-5-支持的模型","link":"#_2-5-支持的模型","children":[]},{"level":2,"title":"2.6　运行时架构","slug":"_2-6-运行时架构","link":"#_2-6-运行时架构","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{},"filePathRelative":"docs/Agent/DeerFlow/02-repo-overview.md"}');export{h as comp,m as data};
